prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER NOT EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8927571B-D906-4AA9-BC57-8B7A376CCB49>
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?reachable WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  OPTIONAL { ?task bbo:name ?taskName . }
  BIND(
    EXISTS {
      <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8927571B-D906-4AA9-BC57-8B7A376CCB49>
        ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    } AS ?reachable
  )
}
